VALUES
  ('aboriginal-6f0ba476-moex-00720', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '我國現行有關長期持有一般用地土地增值稅減徵之規定，下列敘述何者錯誤？', '["持有土地年限超過10年以上者，就其土地增值稅超過最低稅率部分減徵10%", "持有土地年限超過20年以上者，就其土地增值稅超過最低稅率部分減徵20%", "持有土地年限超過30年以上者，就其土地增值稅超過最低稅率部分減徵30%", "持有土地年限超過40年以上者，就其土地增值稅超過最低稅率部分減徵40%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "b7d0013183b4", "answer_pdf_sha1": "43dc4f1cf71e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00721', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'essay', '某國因疫情的封鎖，造成經濟不景氣，該國政府擬以發放現金或消費券
的方式刺激民間消費。請根據經濟理論回答下列問題。
那一種方式帶給人們的效用較高？那一種方式可以真正達到增加消
費的效果？請繪圖說明之。（7 分）
相較於發現金，發放消費券還會延伸那些額外成本？（5 分）
在政策執行上如何使消費券發揮最大功效？（5 分）
若該國為一封閉經濟體，所得稅率為 0.2，而邊際消費傾向為 0.75，且
政府的刺激消費政策可增加民間自主性消費支出200 億元，則該國的
總產出可增加多少？（8分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00722', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'essay', '請回答下列總體經濟現象。（每小題 5 分，共 25分）
為何消費和投資為「順景氣循環（pro-cyclical）變數」？
為何消費的波動性（volatility）會小於產出的波動性？
為何投資的波動性（volatility）會大於產出的波動性？
根據梭羅（Solow）成長理論，在沒有技術進步和人口固定下，長期的
經濟成長率為零，其主要原因為何？
梭羅（Solow）成長理論中，資本累積的黃金法則（goldenrule）的意
義為何？其成立的條件為何？', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00723', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '假設甲、乙兩國有相同數量的生產要素，且兩國都僅生產稻米與甘蔗。若甲國每年可生產50斤稻 米或10斤甘蔗；乙國每年可生產10斤稻米或2斤甘蔗，則下列敘述何者正確？', '["開放甲、乙兩國間的貿易，對甲、乙兩國皆有利", "開放甲、乙兩國間的貿易對甲國不利，僅乙國可從兩國間的貿易獲利", "甲、乙兩國皆無法受惠於兩國間的貿易，因為不論生產稻米或甘蔗，甲國皆具有絕對利益", "甲、乙兩國皆無法受惠於兩國間的貿易，因為不論生產稻米或甘蔗，兩國皆不具有比較利益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00724', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '某漢堡業者在經營多年之後，體認出若採取低價策略將難以生存，由此可能顯示：', '["漢堡的需求彈性很大", "漢堡的需求彈性很小", "漢堡的供給彈性很大", "漢堡的供給彈性很小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00725', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '廠商的生產函數為q = LK，其中q為產量、L為勞動投入量、K則為資本投入量。則此生產函數 替代彈性的值為何？', '["0", "1", "2", "無窮大"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00726', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '在完全競爭市場中，市場需求突然增加將導致：', '["廠商的長期利潤上升", "廠商的短期平均總成本上升", "廠商的長期平均總成本上升", "廠商的短期邊際收益上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00727', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '勞動獨買者所給付的工資率_______邊際勞動成本，並且______邊際勞動產值：', '["等於；等於", "低於；低於", "等於；低於", "低於；等於"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00728', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '政府考量民眾的生活負擔凍漲油價，要求國營企業以低於成本的價格供應汽油。請問政府此舉的 效果是：', '["汽油的交易量會減少", "導致民眾的生活水準下降", "帶來社會福利的無謂損失", "私人企業的汽油產量會上升"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00729', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '某人對X與Y的效用函數為U＝min{X,2Y}。若X與Y的價格分別為10與5且所得為100，則 最適消費數量為：', '["X＝8，Y＝4", "X＝4，Y＝8", "X＝6，Y＝3", "X＝10，Y＝5"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:58+00:00", "source_pdf_sha1": "aff8e6e4a23e", "answer_pdf_sha1": "0a046261f1ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "1106", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
